/**
 * Type of account being displayed
 */
type AccountType = 'financial' | 'data';
/**
 * Individual account data structure
 */
interface AccountData {
    /**
     * Unique identifier for the account
     */
    id: string;
    /**
     * Type of account (financial or data)
     */
    type: AccountType;
    /**
     * Main balance amount to display
     */
    balance: string;
    /**
     * Label above the balance (e.g., "Total balance", "Available balance")
     */
    balanceLabel: string;
    /**
     * Optional secondary information below the balance
     * For financial: could be currency name, last updated
     * For data: storage info like "of 200GB"
     */
    secondaryInfo?: string;
}
/**
 * Props for AccountsRail root component
 */
