/**
 * StructuredList - A flexible micropattern for organizing content with header, items, and footer sections.
 *
 * The StructuredList provides a three-slot composition pattern:
 * 1. **Header**: Headline, title, or custom navigation (e.g., tabs)
 * 2. **Items**: List, grid, or carousel of content
 * 3. **Footer**: Action button or disclaimer text
 *
 * ## Features
 * - Three layout modes: list (vertical), grid (responsive), carousel (horizontal scroll)
 * - Flexible API: supports both composition (children) and data-driven (items prop) approaches
 * - Compound components for common header/footer variants
 * - Token-driven spacing and typography
 * - React ARIA accessibility support
 * - Mobile-first, responsive design
 * - Padding variations for card or edge-to-edge usage
 *
 * ## Usage Patterns
 *
 * ### Basic List with Header and Footer
 * ```tsx
 * <StructuredList
 *   header={
 *     <StructuredList.Header
 *       variant="headline"
 *       text="Transactions"
 *       action={<Icon asset={<IcMore />} />}
 *       onActionPress={() => {}}
 *     />
 *   }
 *   footer={
 *     <StructuredList.Footer
 *       variant="button"
 *       text="See more"
 *       onPress={() => {}}
 *     />
 *   }
 * >
 *   <ListItem leading={<Avatar />} label="Surendra Yadav" trailing="₹500" />
 *   <ListItem leading={<Avatar />} label="Uber India" trailing="₹130.81" />
 * </StructuredList>
 * ```
 *
 * ### Data-Driven Approach
 * ```tsx
 * <StructuredList
 *   items={transactions}
 *   renderItem={(item) => (
 *     <ListItem
 *       leading={<Avatar name={item.name} />}
 *       label={item.name}
 *       trailing={item.amount}
 *     />
 *   )}
 *   keyExtractor={(item) => item.id}
 * />
 * ```
 *
 * ### Grid Layout
 * ```tsx
 * <StructuredList>
 *   <StructuredList.Items layout="grid" columns={2}>
 *     <Card />
 *     <Card />
 *   </StructuredList.Items>
 * </StructuredList>
 * ```
 *
 * ### Carousel Layout
 * ```tsx
 * <StructuredList>
 *   <StructuredList.Items layout="carousel" showIndicators>
 *     <AccountCard />
 *     <AccountCard />
 *   </StructuredList.Items>
 * </StructuredList>
 * ```
 *
 * ### Edge-to-Edge Layout (No Padding)
 * ```tsx
 * <StructuredList disablePadding>
 *   <StructuredList.Header variant="title" text="Pay options" />
 *   <StructuredList.Items layout="list">
 *     <ListItem showDivider />
 *   </StructuredList.Items>
 *   <StructuredList.Footer variant="text" text="Disclaimer..." />
 * </StructuredList>
 * ```
 *
 * ### Custom Header (Tabs)
 * ```tsx
 * <StructuredList
 *   disablePadding
 *   header={
 *     <Tabs>
 *       <Tab>Investments</Tab>
 *       <Tab>Goals</Tab>
 *     </Tabs>
 *   }
 * >
 *   <ListItem />
 * </StructuredList>
 * ```
 *
 * @example
 * // LLM-friendly example: Complete transaction list
 * <StructuredList>
 *   <StructuredList.Header
 *     variant="headline"
 *     text="Recent Transactions"
 *     action={<Icon asset={<IcMore />} />}
 *   />
 *   <StructuredList.Items layout="list">
 *     <ListItem label="Payment" trailing="₹500" />
 *     <ListItem label="Refund" trailing="₹100" />
 *   </StructuredList.Items>
 *   <StructuredList.Footer variant="button" text="View all" />
 * </StructuredList>
 */
